"""
MKT Christ — 1 Samuel chapters 1–3
Run: python3 scripts/zc-christ-1samuel-1-3-full.py

Ch1:  Hannah's barrenness, vow, Samuel's birth and dedication (28 verses)
Ch2:  Hannah's prayer/song; Eli's corrupt sons; Samuel grows; faithful priest oracle (36 verses)
Ch3:  Samuel's call; word of YHWH; Samuel established as prophet (21 verses)

Key Christological themes:
- Hannah's barren-woman-receives-promised-son pattern → virgin birth via Mary's Magnificat echo
- Samuel's dedication at Shiloh → Jesus presented at temple (Luke 2:22-24)
- Hannah's song → Mary's Magnificat (Luke 1:46-55)
- mashiach (2:10) — first use of the anointed-king term pointing to Messiah
- Faithful priest oracle (2:35) → Christ as the true faithful high priest (Heb 7)
- YHWH raises from Sheol (2:6) → resurrection pattern
- Samuel grows in favor with YHWH and men (2:26) → Luke 2:52
- Word of YHWH rare (3:1) → John 1:14 (Word became flesh, ending the silence)
- Samuel's call pattern → apostolic call; hinneni formula of covenant availability
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "1": {
    "1": "<p>Elkanah's five-generation Ephraimite genealogy establishes Samuel's origins in the tribal structure of Israel. The genealogy is transitional setup: Samuel will be the last judge and first of the great prophets, the human hinge between the age of judges and the age of kings. Christ's genealogy in Matthew 1 serves the same structural function — establishing his place in the covenant history before announcing the decisive new beginning. The genealogical form signals that what follows is the continuation and climax of YHWH's covenant story.</p>",
    "2": "<p>Hannah's barrenness (<em>YHWH had closed her womb</em>, v5) places her in the line of the barren women through whom YHWH sovereignly initiates his redemptive purposes: Sarah (Gen 11:30; 21:1-2), Rebekah (Gen 25:21), Rachel (Gen 29:31; 30:22-24), and Samson's unnamed mother (Judg 13:2-3). Each barren woman who conceives by divine opening is a type of the impossible birth that YHWH alone can accomplish. The pattern culminates in Mary's virginal conception — the ultimate impossible birth, where the womb is opened not from barrenness but from virginity, and the child born is not a prophet or judge but the Son of God himself.</p>",
    "3": "<p>Elkanah's annual pilgrimage to Shiloh to worship and sacrifice before YHWH Sabaoth establishes the household's covenant fidelity. The faithful father making annual pilgrimage to the sanctuary echoes the pattern of Joseph and Mary's annual pilgrimage to Jerusalem (Luke 2:41-42) — the same act of covenant devotion that frames the episode of twelve-year-old Jesus remaining in the temple. In both cases, the annual pilgrimage to the sanctuary becomes the occasion for a divine disclosure about the child who will change history.</p>",
    "4": "<p>Elkanah distributes portions to Peninnah and her children at the festival sacrifice — the ordinary economics of a polygamous household navigating covenant worship. The distribution of sacrificial portions at the annual feast is the backdrop against which Hannah's double portion and empty womb create the narrative tension. Christ at the Last Supper distributes the elements — his body and blood — to his disciples: the sacrificial meal becomes the defining act of the new covenant as it was the context for the Shiloh covenant meal.</p>",
    "5": "<p>Elkanah gives Hannah a double portion because he loves her, though YHWH had closed her womb. The double portion (<em>manah ʾaḥat ʾappāyim</em>) of special love for the childless wife anticipates the pattern of divine favor on the humanly disadvantaged. YHWH's closing of the womb is sovereign, purposeful, and temporary — a preparation for intervention, not a permanent exclusion. The pattern: special love accompanies the unfulfilled promise, and YHWH's own timing will supply what human biology cannot. This is the economy of grace that Paul identifies in 1 Cor 1:27-29: YHWH chooses what is humanly unable to produce.</p>",
    "6": "<p>Peninnah provokes Hannah bitterly year after year because YHWH had closed her womb — the adversary mocking the one whom YHWH has chosen. This structure of the chosen-but-disadvantaged person mocked by a rival echoes throughout the OT: Joseph mocked by brothers, David despised by Saul, the Servant of Isaiah despised and rejected. The adversary's provocation intensifies the distress that drives the chosen one to prayer. Christ, despised and rejected by men (Isa 53:3), is the ultimate fulfillment of this pattern: the Chosen One of God most deeply mocked at Calvary.</p>",
    "7": "<p>The annual provocation — every time Hannah went up to the house of YHWH — makes the sanctuary itself the site of her suffering. The place of YHWH's presence is the place where Hannah's unresolved pain is most acute. This is the theology of lament: the pain is not hidden from YHWH but brought to his face. Christ in Gethsemane brings his deepest anguish to the Father in prayer (Luke 22:41-44) — the same pattern of the beloved of God not suppressing suffering but expressing it in the Father's presence.</p>",
    "8": "<p>Elkanah's comfort — &#8220;Am I not more to you than ten sons?&#8221; — is genuine but insufficient. The human love of the closest earthly relationship cannot substitute for the unfulfilled divine promise. Hannah's grief persists because her longing is ultimately about YHWH's purpose, not merely personal desire. Christ's disciples are comforted by his presence but still await the full fulfillment of the kingdom's coming; human relationship with Christ is genuine but not yet the complete satisfaction it will be in the resurrection (1 John 3:2: we shall be like him when we see him face to face).</p>",
    "9": "<p>Hannah rises after the meal and goes to pray before YHWH while Eli sits at the doorpost of the temple. The spatial arrangement — Hannah approaching the sanctuary while the priest sits at the threshold — is significant. The legitimate sacrificial system, represented by Eli, is present but passive; the direct, personal, desperate prayer of a covenant woman is the active channel for the divine response. Christ's high priestly ministry similarly positions him as the one who, from the true sanctuary, is responsive to the desperate prayers of his people (Heb 7:25: he always lives to make intercession for those who draw near to God through him).</p>",
    "10": "<p>Hannah prayed to YHWH with deep bitterness of soul, weeping bitterly (<em>tibke bāḵôʾ</em>). The intensity of her prayer — the bitterness, the tears, the completeness of her desperation — is the pattern of authentic petition that characterizes OT lament and NT prayer. Jesus wept (John 11:35) at Lazarus's tomb; he offered up prayers with loud cries and tears during his earthly life (Heb 5:7). The Servant who carries sorrows (Isa 53:4) is pre-figured in the sorrowful woman whose prayer becomes the instrument of divine action.</p>",
    "11": "<p>Hannah's vow: if YHWH will look on her misery and give her a son, she will give him back to YHWH all his days, and no razor shall touch his head — a Nazirite dedication. The vow structure is reciprocal: Hannah gives YHWH her need, and in return gives back whatever is given. This is the theology of consecration: the gift received from YHWH is returned to YHWH for his purposes. Christ &#8220;for the joy set before him endured the cross&#8221; (Heb 12:2) — wholly consecrated to the Father's purposes. Hannah's Nazirite vow for Samuel (never cutting the hair) signals that this son belongs entirely to YHWH's service from birth.</p>",
    "12": "<p>As Hannah continued praying before YHWH, Eli watched her mouth. The priest's surveillance of the praying woman — assuming drunkenness rather than genuine devotion — is a first marker of Eli's diminished spiritual perception. He sees the form of prayer (moving lips) but cannot discern its substance (deep intercession). The religious establishment observing but not understanding the authentic spiritual transaction taking place is a pattern Christ addresses repeatedly: the Pharisees who see his miracles but attribute them to Beelzebul (Matt 12:24), the scribes who observe his ministry but cannot perceive its true nature.</p>",
    "13": "<p>Hannah prays in her heart — her lips move but her voice is not heard. Eli, seeing only the external behavior, judges her as drunk. The misidentification of genuine prayer as intoxication is the ironic contrast between surface reading and spiritual reality. Paul describes the Spirit's deep intercession in similar terms: &#8220;the Spirit himself intercedes for us with groanings too deep for words&#8221; (Rom 8:26) — prayer that cannot be verbalized is the most profound form. Hannah's silent but deep prayer is the model that Paul will theologically articulate for those whose Spirit-filled intercession goes beyond ordinary language.</p>",
    "14": "<p>Eli's rebuke — &#8220;How long are you going to be drunk? Put your wine away&#8221; — is an institutional false accusation of the genuinely righteous. The pattern of the legitimate religious authority wrongly accusing the genuinely faithful is the structure fulfilled in the trial of Jesus: the high priest and council pronouncing Jesus guilty on the basis of misreading who he truly is (Matt 26:65-66: &#8220;he has spoken blasphemy&#8221;). In both cases the institutional representative of the covenant community misidentifies the most faithful person before him.</p>",
    "15": "<p>Hannah's defense — &#8220;I am a woman deeply troubled in spirit; I have drunk neither wine nor strong drink, but I have been pouring out my soul before YHWH&#8221; — is an appeal to inner spiritual reality over external appearance. The phrase &#8220;pouring out my soul&#8221; (<em>špk napšî</em>) is the idiom for total self-disclosure before YHWH (Ps 62:8; Lam 2:19). Christ's high priestly prayer in John 17 is the supreme example of this complete outpouring before the Father on behalf of his people. Hannah models the transparent, vulnerable prayer that characterizes the covenant person in extremity.</p>",
    "16": "<p>&#8220;Do not take your servant for a worthless woman (<em>bat-bĕliyyaʿal</em>) — for I have been speaking from my great anxiety and grief.&#8221; The self-designation as <em>ʾāmāh</em> (female servant/slave) twice in this verse is Hannah's identification with the lowest covenant category — not claiming rights but appealing entirely to YHWH's grace. This is the posture of the publican in Jesus's parable (Luke 18:13: &#8220;God, be merciful to me, a sinner&#8221;) versus the Pharisee's self-presentation. Christ himself takes the form of a servant (<em>doulos</em>, Phil 2:7) — the divine Son occupying the lowest relational position to accomplish what no other position could accomplish.</p>",
    "17": "<p>Eli's pronouncement — &#8220;Go in peace, and may the God of Israel grant your petition that you have asked of him&#8221; — functions as a priestly oracle. The priest who moments ago accused Hannah of drunkenness now speaks YHWH's word of blessing over her. The same human authority that wrongly accused becomes the instrument of divine commissioning. This is the pattern of Acts 2: the same Jerusalem crowd that participated in crucifying Jesus becomes the first recipients of Peter's Pentecost sermon and the first converts. The instrument of condemnation becomes the instrument of blessing.</p>",
    "18": "<p>&#8220;Let your servant find favor in your eyes&#8221; — and she ate, drank, and her face was sad no more. The transformation is immediate: before any physical sign of answer, before conception, Hannah's face changes. This is faith receiving the promise as though it were already accomplished — what Heb 11:1 defines as &#8220;the assurance of things hoped for, the conviction of things not seen.&#8221; Christ's pattern of declaring &#8220;your faith has saved/healed you&#8221; (Luke 7:50; 17:19) operates on the same principle: the divine word received in faith effects the transformation before the physical evidence is complete.</p>",
    "19": "<p>Elkanah knew his wife, and YHWH remembered her (<em>wayyizkorāh YHWH</em>). The divine &#8220;remembering&#8221; is the covenant-activation verb: YHWH remembers Noah (Gen 8:1), remembers Abraham when destroying Sodom (Gen 19:29), remembers Rachel (Gen 30:22). Divine remembering is not recovery from forgetfulness but the moment of covenant promise being enacted. The same verb appears in Luke 1:54-55 in Mary's Magnificat: &#8220;he has helped his servant Israel, in remembrance of his mercy, as he spoke to our fathers&#8221; — the Magnificat explicitly identifies Christ's coming as YHWH's covenant remembering.</p>",
    "20": "<p>Hannah conceived and bore a son and called his name Samuel — &#8220;for I have asked him of YHWH.&#8221; The name <em>šĕmûʾēl</em> (asked/heard of God) encodes the theology of petitionary prayer answered: the child's entire existence is a declaration that YHWH hears prayer. Contrast Jesus: his name is &#8220;YHWH saves&#8221; (<em>yēšûaʿ</em>) — the name encodes not the prayer but the answer; not the asking but the salvation that is the ultimate answer to all human asking (Matt 1:21: &#8220;you shall call his name Jesus, for he will save his people from their sins&#8221;). Samuel is the asked-for; Jesus is the saving answer.</p>",
    "21": "<p>Elkanah goes to offer the yearly sacrifice and fulfill his vow. Hannah stays back, explaining she will bring the child when weaned — &#8220;that he may appear before YHWH and dwell there forever.&#8221; The phrase &#8220;dwell there forever&#8221; (<em>yāšaḇ šām ʿaḏ-ʿôlām</em>) anticipates the permanent dedication of Samuel to Shiloh. Christ, who ascended and is seated permanently at the right hand of the Father (Heb 1:3; 10:12), &#8220;dwells there forever&#8221; in the truest sense — his high priestly presence in the heavenly sanctuary is permanent, not seasonal like the Levitical round of annual sacrifices.</p>",
    "22": "<p>Hannah will not go up until the child is weaned — &#8220;then I will bring him, that he may appear before YHWH and remain there forever.&#8221; The weaning period (typically 2-3 years in the ancient world) was the period of formation under the mother before formal dedication. Christ's &#8220;hidden years&#8221; in Nazareth — the 30 years before his public ministry — serve a parallel function: the period of formation (growing in wisdom and stature, Luke 2:52) before appearing publicly as YHWH's servant. Both Samuel and Christ are prepared in hiddenness before their public dedication.</p>",
    "23": "<p>Elkanah's blessing — &#8220;Only, may YHWH confirm his word&#8221; (<em>yāqēm YHWH ʾet-dĕḇārô</em>) — is the faith-confession of the father who entrusts the divine promise to YHWH's faithfulness. The petition that YHWH establish/confirm his word is the prayer of every generation awaiting messianic fulfillment. Simeon in Luke 2:25-32 represents the accumulated waiting of all who prayed &#8220;may YHWH confirm his word&#8221; — and at the temple presentation his prayer is answered: he holds the one who is YHWH's word confirmed.</p>",
    "24": "<p>Hannah brings the weaned Samuel to Shiloh with a three-year-old bull, an ephah of flour, and a skin of wine — a substantial offering accompanying the dedication. The parallel in Luke 2:22-24 is explicit: Mary and Joseph bring the infant Jesus to the temple in Jerusalem to present him to the Lord, as it is written in the law of Moses. The dedication of the firstborn son at the sanctuary — Samuel at Shiloh, Jesus at Jerusalem — is the same typological structure. Both presentations are accompanied by sacrificial offerings; both children are formally consecrated to YHWH's service at the sanctuary.</p>",
    "25": "<p>The bull was slaughtered and the child brought to Eli. The sacrificial killing that accompanies Samuel's presentation at the sanctuary is the ritual backdrop that prefigures the greater presentation: Christ&#8217;s presentation before the Father is accomplished through his own sacrificial death, not an animal substitute. The book of Hebrews (Heb 9:11-14; 10:5-10) makes this explicit: the animal sacrifices of the Levitical system were shadows of the one true self-offering that would abolish the need for further sacrifice. Samuel is presented at the sanctuary after the bull's death; Christ enters the true sanctuary through his own blood (Heb 9:12).</p>",
    "26": "<p>Hannah&#8217;s self-identification: &#8220;I am the woman who was standing here in your presence praying to YHWH.&#8221; The fulfilled-prayer testimony — &#8220;for this child I prayed, and YHWH has granted me my petition&#8221; — is the pattern of all realized-promise confession. The NT counterpart is Simeon's &#8220;Lord, now you are letting your servant depart in peace, according to your word; for my eyes have seen your salvation&#8221; (Luke 2:29-30) — the long-prayed-for becomes the held-in-arms reality. Hannah models the testimony that transforms private faith into public witness.</p>",
    "27": "<p>&#8220;For this child I prayed, and YHWH has granted me my petition that I asked of him.&#8221; The completion-of-prayer testimony is the basis for the return-to-YHWH dedication: because YHWH answered, the gift is returned. The pattern of received grace motivating consecration is Paul&#8217;s logic in Romans 12:1: &#8220;in view of God&#8217;s mercies, offer your bodies as a living sacrifice.&#8221; Christ himself offers the supreme example: receiving everything from the Father (John 3:35: all things have been given into his hands), he returns everything to the Father in the cross and exaltation (1 Cor 15:28: the Son himself will be subjected to him).</p>",
    "28": "<p>&#8220;Therefore I have given him back to YHWH. As long as he lives, he belongs to YHWH.&#8221; Samuel&#8217;s lifelong dedication to YHWH at Shiloh is the pattern for the consecrated life that receives its purpose entirely from YHWH&#8217;s call. Christ&#8217;s self-description &#8220;I do not seek my own will but the will of him who sent me&#8221; (John 5:30) is the perfect instantiation of this dedication: completely given to YHWH&#8217;s purpose, belonging entirely to the Father. The <em>hinnēnî</em> (here I am) formula — which Samuel will use when YHWH calls him in ch3 — is the verbal expression of this total consecration.</p>"
  },
  "2": {
    "1": "<p>Hannah&#8217;s song opens: &#8220;My heart rejoices in YHWH; my horn is exalted in YHWH; my mouth speaks boldly against my enemies.&#8221; Mary&#8217;s Magnificat (Luke 1:46-55) is the conscious NT echo and expansion of Hannah&#8217;s song — both begin with the soul/heart rejoicing in YHWH as Savior, both announce the reversal of the powerful and the exaltation of the lowly, both celebrate YHWH&#8217;s faithful remembrance of his covenant. The structural and linguistic parallels are so close that Luke intends the reader to hear Hannah in Mary. Hannah&#8217;s son Samuel and Mary&#8217;s son Jesus are the two great &#8220;asked-for&#8221; and &#8220;given&#8221; children whose births inaugurate new covenantal eras.</p>",
    "2": "<p>&#8220;There is none holy like YHWH; there is no one besides you; there is no rock like our God.&#8221; The incomparable holiness of YHWH — his uniqueness and absolute otherness — is the theological foundation of the song. The christological implication: YHWH&#8217;s incomparable holiness is what makes the incarnation so theologically momentous. When Paul writes &#8220;in him the whole fullness of deity dwells bodily&#8221; (Col 2:9), he is claiming that this incomparable YHWH — the one for whom there is no comparison — has taken human form. The holiness celebrated in Hannah&#8217;s song becomes embodied in Christ.</p>",
    "3": "<p>&#8220;Do not speak with such great pride; let no arrogance come from your mouth, for YHWH is a God of knowledge, and by him actions are weighed.&#8221; YHWH&#8217;s perfect knowledge includes the weighing of all actions — the divine accounting that no human boast can escape. Christ&#8217;s claim to judge all humanity (John 5:22: the Father has given all judgment to the Son; Matt 25:31-46: the Son of Man judges all nations) is the incarnate expression of this divine attribute. The judge who weighs actions is the one who himself was weighed (Dan 5:27 uses the same concept) and found perfectly righteous — making him the only qualified judge.</p>",
    "4": "<p>&#8220;The bows of the mighty are shattered, but those who stumbled are girded with strength.&#8221; The reversal pattern — the powerful brought down, the weak empowered — is the recurring shape of YHWH&#8217;s saving activity. Mary&#8217;s Magnificat echoes: &#8220;he has brought down the mighty from their thrones and exalted those of humble estate&#8221; (Luke 1:52). The crucifixion is the ultimate expression of this reversal: the apparently defeated Messiah (bows shattered) is raised in resurrection power (girded with strength). The one who stumbled under the cross rises as the one who has defeated every power.</p>",
    "5": "<p>&#8220;Those who were full have hired themselves out for bread, but those who were hungry are hungry no more. The barren has borne seven, but she who has many children is desolate.&#8221; The economic and reproductive reversals continue the pattern. The barren woman bearing seven is Hannah&#8217;s own narrative transformed into cosmic principle. Jesus&#8217;s Beatitudes (Matt 5:3-12; Luke 6:20-26) are the kingdom proclamation of this same principle: the hungry will be filled, the mourning will be comforted, the poor inherit the kingdom. The resurrection is the ultimate satiation of the hungry: those who hunger for righteousness (Matt 5:6) will be fully satisfied.</p>",
    "6": "<p>&#8220;YHWH brings death and gives life; he brings down to Sheol and raises up.&#8221; This is the OT&#8217;s clearest pre-Mosaic statement of YHWH&#8217;s sovereignty over death — including the capacity for resurrection (<em>môrîḏ šĕʾôl wayyāʿal</em>, brings down to Sheol and raises up). Paul quotes this verse&#8217;s theology implicitly in 2 Cor 1:9 (&#8220;God who raises the dead&#8221;) and explicitly grounds the resurrection hope in YHWH&#8217;s resurrection-power (1 Cor 15:20-22). Christ&#8217;s resurrection is the supreme instantiation of YHWH&#8217;s declared power: he who brought down to Sheol raised up the Son who descended into death.</p>",
    "7": "<p>&#8220;YHWH makes poor and makes rich; he brings low, and he also lifts up.&#8221; The sovereign control over both poverty and wealth, lowness and height, is ascribed exclusively to YHWH. James 1:9-10 applies this principle to the gospel community: the lowly brother boasts in his exaltation, the rich in his humiliation — because YHWH&#8217;s sovereign reversal is operative in Christ. Christ himself is the embodiment of both directions: he became poor so that by his poverty we might become rich (2 Cor 8:9 — the preeminent application of Hannah&#8217;s YHWH-makes-poor-and-rich theology).</p>",
    "8": "<p>&#8220;He raises the poor from the dust and lifts the needy from the ash heap, to seat them with princes and give them a seat of honor.&#8221; Mary&#8217;s Magnificat is almost verbatim: &#8220;he has exalted those of humble estate&#8221; (Luke 1:52). The image of the ash-heap poor seated with princes is realized in Christ&#8217;s table fellowship with sinners (Luke 15:1-2) — the ultimate inversion of social honor. Rev 3:21 extends the image eschatologically: the overcomer will sit with Christ on his throne, as he sat down with his Father on his throne. The ash-heap to throne trajectory is the shape of gospel salvation.</p>",
    "9": "<p>&#8220;He will guard the feet of his faithful ones, but the wicked will be silenced in darkness, for not by strength does one prevail.&#8221; The guarding of the <em>ḥăsîḏîm</em> (faithful/covenant-loyal) is YHWH&#8217;s protective faithfulness toward those who belong to him. John 10:28-29 expresses the same guarantee: &#8220;no one will snatch them out of my hand ... no one can snatch them out of the Father&#8217;s hand.&#8221; The phrase &#8220;not by strength does one prevail&#8221; is the anti-Darwinian principle that Paul applies to the cross: &#8220;the foolishness of God is wiser than men, and the weakness of God is stronger than men&#8221; (1 Cor 1:25).</p>",
    "10": "<p>&#8220;YHWH will judge the ends of the earth; he will give strength to his king and exalt the horn of his anointed (<em>māšîḥô</em>).&#8221; This verse contains the OT&#8217;s first use of <em>māšîaḥ</em> (anointed one) in the context of YHWH&#8217;s eschatological king — the term from which &#8220;Messiah&#8221; and &#8220;Christ&#8221; (Greek <em>christos</em>) derive their meaning. The prayer of a barren woman at Shiloh ends with an oracle about the coming cosmic king who will judge the ends of the earth. Luke explicitly connects Hannah&#8217;s song to Mary&#8217;s Magnificat (Luke 1:46-55), making Mary&#8217;s child the one who fulfills this closing oracle: Jesus is YHWH&#8217;s <em>māšîaḥ</em>, whose horn YHWH exalts through resurrection and exaltation (Acts 2:36).</p>",
    "11": "<p>Samuel ministers before YHWH in the presence of Eli. The young child faithfully serving in the sanctuary while the legitimate priestly structure around him is corrupt is the pattern of the faithful remnant within a failed institution. Christ, who declared &#8220;zeal for your house will consume me&#8221; (John 2:17, citing Ps 69:9), represents the same pattern: the truly faithful one present in the sanctuary while the surrounding religious establishment has lost its way. Samuel&#8217;s quiet faithfulness is the seed of the prophetic renewal that will replace the corrupt Elide priesthood.</p>",
    "12": "<p>&#8220;Now the sons of Eli were worthless men (<em>bĕnê bĕliyyaʿal</em>); they did not know YHWH.&#8221; The contrast between the corrupt official priests and the faithful servant Samuel structures chapters 2-3. The failure of the established priestly house — those who should mediate between YHWH and Israel but instead exploit the system — creates the context for YHWH&#8217;s institution of a new order. Hebrews 7:11-12 argues precisely this: the Levitical priesthood&#8217;s failure to produce perfection necessitated a different priest arising from a different order (Melchizedek) — Christ is YHWH&#8217;s answer to the failure of the Elide pattern writ large.</p>",
    "13": "<p>The priests&#8217; servant would come with a three-pronged fork while the sacrificial meat was still boiling and take whatever the fork brought up. The priestly appropriation of the sacrificial offering before YHWH&#8217;s portion was consecrated represents the inversion of the proper order: taking for themselves what belongs first to YHWH. The prophetic critique of false priests who feed themselves at the expense of the flock is collected in Ezekiel 34 and forms the background for Christ&#8217;s &#8220;I am the good shepherd&#8221; (John 10:11) — the contrast between exploitative shepherds/priests and the one who lays down his life rather than taking life for himself.</p>",
    "14": "<p>The cook would thrust the fork into the pan, kettle, cauldron, or pot, and whatever the fork brought up the priest would take. The greedy extraction from every vessel of the sacrifice is a comprehensive corruption: no part of the covenantal meal escapes the priests&#8217; exploitation. Christ&#8217;s cleansing of the temple (Matt 21:12-13; John 2:13-17) is the direct action against this same pattern of exploitation at the sacred site — the Father&#8217;s house turned into a den of robbers by those whose position should make them its servants.</p>",
    "15": "<p>Before the fat was burned — before YHWH&#8217;s portion was consecrated — the priest&#8217;s servant demanded the raw meat. The timing is the theological issue: YHWH&#8217;s portion was the fat (Lev 3:16-17), which was to be burned first. Demanding the meat before YHWH receives his due inverts the covenant priority. The Pharisees&#8217; tithing of mint, dill, and cumin while neglecting justice, mercy, and faithfulness (Matt 23:23) is the same inversion: technical compliance with religious form while missing the substance of what YHWH requires. Jesus restores the priority: &#8220;seek first the kingdom of God and his righteousness&#8221; (Matt 6:33).</p>",
    "16": "<p>When the offerer requested that the fat be burned first, the priest&#8217;s servant replied, &#8220;No, hand it over now, or I&#8217;ll take it by force.&#8221; The use of force to override legitimate covenant protocol is the corruption of sacred office into coercion. Jesus describes his own ministry in direct contrast: &#8220;The Son of Man came not to be served but to serve, and to give his life as a ransom for many&#8221; (Matt 20:28). The one who could have taken everything by right instead gave everything — the absolute inversion of Hophni and Phinehas&#8217;s pattern.</p>",
    "17": "<p>&#8220;The sin of these young men was very great in the sight of YHWH, for they treated YHWH&#8217;s offering with contempt (<em>bāzāh</em>).&#8221; The term <em>bāzāh</em> (to despise/treat with contempt) is the verb used for Esau despising his birthright (Gen 25:34) and for the despising of the Servant of YHWH in Isa 53:3 (&#8220;he was despised and we esteemed him not&#8221;). The priests who despise YHWH&#8217;s offering are ultimately contemning the entire sacrificial system — and by extension, the one to whom all sacrifice pointed. Christ, despised and rejected by the religious establishment, is the ultimate offering treated with contempt.</p>",
    "18": "<p>&#8220;Samuel was ministering before YHWH, a young boy clothed in a linen ephod.&#8221; The linen ephod (<em>ʾēp̄ôḏ bāḏ</em>) was the priestly garment — here worn by the child Samuel, marking his priestly service even at this young age. The contrast with the corrupt priests is stark: while Hophni and Phinehas exploit their priestly office, the child Samuel serves faithfully in priestly garments. Christ &#8220;a priest forever after the order of Melchizedek&#8221; (Ps 110:4; Heb 7:17) is the ultimate faithful priest — not exploiting but offering, not extracting but giving.</p>",
    "19": "<p>Hannah brought Samuel a small robe each year when she came with Elkanah for the annual sacrifice. The mother&#8217;s annual care for the dedicated child — the robe growing with each year&#8217;s visit — is a tender portrait of the persistence of maternal love across the distance of consecrated service. Mary, whose son was consecrated from conception, stands at the cross while he hangs dying (John 19:25) — maternal love present at the cost of separation that Samuel&#8217;s dedication cost Hannah. Both mothers give their sons entirely to YHWH&#8217;s purpose.</p>",
    "20": "<p>Eli&#8217;s blessing over Elkanah and Hannah — &#8220;may YHWH give you children by this woman in return for the gift she has given to YHWH&#8221; — is the priestly benediction that invokes covenant reciprocity: give to YHWH, receive from YHWH in return. The principle is expressed in Christ&#8217;s teaching: &#8220;give, and it will be given to you&#8221; (Luke 6:38); &#8220;whoever loses his life for my sake will find it&#8221; (Matt 16:25). Hannah&#8217;s giving of Samuel and receiving of five more children (v21) is the enacted parable of resurrection-logic: what is given in death is returned in abundance.</p>",
    "21": "<p>YHWH visited Hannah and she conceived and bore three sons and two daughters. Meanwhile Samuel grew before YHWH. The divine visitation (<em>pāqaḏ</em>) that produces new life is the covenant-faithfulness pattern; the verb is used of YHWH visiting Sarah (Gen 21:1) and will be used in Luke 1:68 (&#8220;God has visited and redeemed his people&#8221;) in Zechariah&#8217;s benediction at John&#8217;s birth. The divine visitation of Hannah (five more children) and of Israel (Christ) are part of the same pattern of YHWH&#8217;s faithfulness to those who consecrate what they have to him.</p>",
    "22": "<p>Eli heard everything his sons were doing — including how they lay with the women who served at the entrance to the tent of meeting. The sexual exploitation of women who served at the sanctuary — the final and most comprehensive degradation of the priestly office — is the complete inversion of the sanctuary&#8217;s holiness. Christ&#8217;s protection of the vulnerable (Matt 19:14; John 8:10-11) and his explicit condemnation of those who exploit the weak (Matt 18:6: &#8220;whoever causes one of these little ones to stumble, it would be better for him to have a great millstone hung around his neck&#8221;) stands in absolute contrast to the Elide corruption.</p>",
    "23": "<p>Eli&#8217;s rebuke of his sons: &#8220;Why do you do such things? For I hear of your evil deeds from all these people.&#8221; The rebuke is verbal without executive consequence — Eli hears and speaks but does not remove his sons from office. The gap between knowing and acting is the diagnostic of Eli&#8217;s failure. Christ&#8217;s faithfulness in contrast: he not only spoke prophetically against the temple&#8217;s corruption but acted in the cleansing (Matt 21:12-13). The prophet who only speaks without acting upon the word he speaks is a diminished form of the one who is both word and deed.</p>",
    "24": "<p>&#8220;No, my sons, it is not a good report that I hear YHWH&#8217;s people spreading.&#8221; Eli&#8217;s concern centers on reputation — what the people are saying — rather than on the covenant violation itself. The therapeutic pastor who manages reputation rather than confronting sin is the failure mode Eli models. Prophetic faithfulness means speaking the truth even when it destroys reputation: John the Baptist condemning Herod&#8217;s marriage (Matt 14:4), Paul opposing Peter to his face (Gal 2:11), Christ calling the Pharisees whitewashed tombs (Matt 23:27). Eli&#8217;s soft rebuke is the model that prophetic faithfulness must not follow.</p>",
    "25": "<p>&#8220;If one person sins against another, God can mediate for him, but if someone sins against YHWH, who will intercede for him?&#8221; (<em>ûmî yiṯpallel-lô</em>). The rhetorical question — who will intercede for sins against YHWH himself? — is the problem Christ answers. Heb 7:25: &#8220;he always lives to make intercession&#8221; for those who draw near to God through him. The question raised by Eli&#8217;s failed intercession (he prays for his sons but it accomplishes nothing because he has not acted) is the question Christ&#8217;s high priestly ministry answers: the one whose intercession is eternally effective because it is grounded in his own atoning sacrifice.</p>",
    "26": "<p>&#8220;The young Samuel continued to grow and to be in favor with YHWH and with men.&#8221; Luke 2:52 is nearly verbatim: &#8220;And Jesus increased in wisdom and in stature and in favor with God and man.&#8221; Luke&#8217;s language in describing Jesus&#8217;s boyhood is a conscious echo of Samuel&#8217;s growth description — establishing Jesus as the new Samuel, the greater prophet and servant who grows in faithfulness where Eli&#8217;s sons grow in corruption. The parallelism between Samuel and Jesus is one of Luke&#8217;s deliberate literary strategies for presenting Jesus as the fulfillment of the Samuel pattern.</p>",
    "27": "<p>The man of God&#8217;s oracle to Eli begins: &#8220;Did I not reveal myself to your father&#8217;s house when they were in Egypt?&#8221; — the historical recital that grounds the judgment in YHWH&#8217;s prior grace. The pattern of covenant lawsuit (reciting prior grace before announcing judgment) is the structure of both prophetic judgment oracles and Christ&#8217;s seven letters to the churches in Revelation 2-3 (&#8220;I know your works... but I have this against you&#8221;). YHWH&#8217;s judgment comes after, and because of, his grace — which makes the failure more culpable.</p>",
    "28": "<p>&#8220;I chose your ancestor from all the tribes of Israel to be my priest, to go up to my altar, to burn incense, and to wear an ephod before me.&#8221; The priestly election — chosen from all tribes for sanctuary service — is a grace the Elide priests have despised. Christ as the chosen High Priest (Heb 5:4-5: no one takes the honor to himself, but is called by God, as Aaron was; so also Christ did not exalt himself to be made high priest, but was appointed by him who said, &#8220;You are my Son&#8221;) fulfills the priestly election without corruption. The chosen priest who honors the one who chose him, rather than exploiting the office.</p>",
    "29": "<p>&#8220;Why then do you despise my sacrifices and my offerings... and honor your sons more than me?&#8221; The displacement of YHWH&#8217;s honor by family loyalty is the structural sin of the Elide priesthood. Christ declares a comparable priority: &#8220;Whoever loves father or mother more than me is not worthy of me&#8221; (Matt 10:37). The one who put loyalty to family before loyalty to YHWH forfeits the covenant office; the one who honors YHWH above family ties (including Christ&#8217;s own apparent rebuke of his mother and brothers in Matt 12:48-50) demonstrates the total consecration that covenant faithfulness requires.</p>",
    "30": "<p>&#8220;I had said that your house and your father&#8217;s house would walk before me forever, but now YHWH declares: Far be it from me, for those who honor me I will honor, but those who despise me will be lightly esteemed.&#8221; The covenant conditionality — YHWH&#8217;s promise conditioned on faithfulness — is the covenant principle that the Elide tragedy embodies. Christ is the only one who fully honors the Father (John 8:49: &#8220;I honor my Father, and you dishonor me&#8221;; 17:4: &#8220;I glorified you on earth, having accomplished the work that you gave me to do&#8221;). Therefore YHWH honors him above all (Phil 2:9-11: the name above every name).</p>",
    "31": "<p>&#8220;See, the days are coming when I will cut off your strength and the strength of your father&#8217;s house, so that no old man will be in your family.&#8221; The judgment against the corrupt priestly house is announced prophetically before it is executed historically. Christ&#8217;s prophetic announcements of judgment (Matt 23:38: &#8220;your house is left to you desolate&#8221;; Matt 24:2: &#8220;not one stone will be left on another&#8221;) follow the same pattern: prophetic word precedes historical execution, and the gap between announcement and fulfillment is the period of mercy and opportunity for repentance.</p>",
    "32": "<p>&#8220;You will look with envy at all the good that will be done for Israel, but there will never be an old man in your family.&#8221; The judgment of watching YHWH&#8217;s blessing flow to others while your own line is cut off is the reversal-of-fortunes pattern applied to judgment rather than salvation. Christ&#8217;s parable of the prodigal son (Luke 15:25-32) captures the same structure: the older brother &#8220;looks with envy&#8221; at the blessing restored to his brother. The covenant blessing that the corrupt house forfeits flows instead to the faithful heir — ultimately to Christ, who receives the inheritance the unfaithful forfeited.</p>",
    "33": "<p>&#8220;The one of yours I do not cut off from my altar will be left to consume your eyes with grief and break your heart.&#8221; Even the survivor of divine judgment within the corrupt line is a source of sorrow rather than consolation — the partial sparing is not redemptive but testimonial to the totality of the judgment. The NT counterpart is Jerusalem&#8217;s destruction in 70 CE: the survivors of the fall witnessed the complete destruction of the temple and sacrificial system that Christ had already declared obsolete (John 4:21: &#8220;neither on this mountain nor in Jerusalem will you worship the Father&#8221;).</p>",
    "34": "<p>&#8220;And this will be the sign for you: both your sons, Hophni and Phinehas, shall die on the same day.&#8221; The prophetic sign — a specific, dateable, simultaneous death of two named individuals — is the verification device that establishes the oracle&#8217;s divine origin. When the sign is fulfilled (4:11), it validates the entire oracle including the coming of the faithful priest. Christ&#8217;s prophecy of Peter&#8217;s denial (Matt 26:34: &#8220;before the rooster crows you will deny me three times&#8221;) functions similarly — a specific, verifiable prophetic sign that, when fulfilled exactly, retroactively validates the prophet&#8217;s divine knowledge.</p>",
    "35": "<p>&#8220;And I will raise up for myself a faithful priest (<em>kōhēn neʾĕmān</em>) who will do what is in my heart and mind. I will build him an enduring house, and he will walk before my anointed (<em>māšîḥî</em>) forever.&#8221; This verse is the OT&#8217;s most explicit anticipation of the Melchizedekian priesthood that Hebrews develops. The &#8220;faithful priest&#8221; oracle has a near fulfillment in Zadok (who replaces the Elide line in Solomon&#8217;s time) but its full fulfillment is in Christ, the high priest who does perfectly what is in the Father&#8217;s heart (John 8:29: &#8220;I always do the things that are pleasing to him&#8221;). The &#8220;enduring house&#8221; (<em>bayit neʾĕmān</em>) is fulfilled in Christ&#8217;s eternal high priestly ministry that, unlike Eli&#8217;s, will never be cut off.</p>",
    "36": "<p>&#8220;And everyone left in your house will come to beg him for a piece of silver or a loaf of bread.&#8221; The reversal is complete: the priestly house that once extracted meat by force (vv13-16) now begs for bread. The deprivation of those who exploited the sanctuary&#8217;s resources is the covenant-justice fulfillment. The theological pattern: those who grasp for what belongs to others end in poverty; those who give up what belongs to them (Christ: &#8220;though he was rich, yet for your sake he became poor&#8221;, 2 Cor 8:9) end in eternal wealth. The economics of grace run consistently counter to the economics of exploitation.</p>"
  },
  "3": {
    "1": "<p>&#8220;The word of YHWH was rare in those days; there was no frequent vision (<em>ḥāzôn nip̄rāṣ</em>).&#8221; The silence of YHWH&#8217;s word — the prophetic famine — frames the pre-Samuel era and creates the context for his call. John 1:14 (&#8220;And the Word became flesh and dwelt among us&#8221;) is the ultimate end of every prophetic silence: the logos that was &#8220;rare&#8221; and partial throughout the OT period became fully and permanently present in the incarnation. Hebrews 1:1-2 identifies this directly: &#8220;Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son.&#8221; Samuel ends the current prophetic silence; Christ ends all prophetic silence permanently.</p>",
    "2": "<p>Eli&#8217;s dim and failing eyes — he could no longer see (<em>kēhôṯ ʿênāyw lōʾ yûḵal lirʾôṯ</em>) — are the physical embodiment of the spiritual condition the narrator has been describing: the official religious leadership that cannot see what YHWH is doing. The prophetic blindness of the establishment that cannot perceive the new thing YHWH is creating is the pattern Jesus identifies in the Pharisees: &#8220;you are blind guides&#8221; (Matt 23:16, 24); &#8220;having eyes they do not see&#8221; (Mark 8:18). The failing vision of the old priestly order is the backdrop against which the new prophetic clarity that Samuel will embody is introduced.</p>",
    "3": "<p>&#8220;The lamp of God had not yet gone out, and Samuel was lying down in the temple of the LORD, near the ark of God.&#8221; The lamp burning all night (Exod 27:20-21) near the ark — YHWH&#8217;s presence — is the last light of the old order, still burning but nearly exhausted. Samuel lies at the threshold of this dying light and is about to receive the new prophetic word. John 1:5 uses the same imagery of light in darkness: &#8220;The light shines in the darkness, and the darkness has not overcome it.&#8221; Christ is the light that the darkness — the prophetic lamp that never goes out — because he is not merely an intermediary of the divine word but the word himself.</p>",
    "4": "<p>&#8220;Then YHWH called, &#8216;Samuel!&#8217; and he said, &#8216;Here I am&#8217; (<em>hinnēnî</em>).&#8221; The <em>hinnēnî</em> response — &#8220;here I am&#8221;, the formula of complete covenant availability — is used by Abraham (Gen 22:1), Moses (Exod 3:4), and Isaiah (Isa 6:8). Samuel&#8217;s <em>hinnēnî</em> in response to what he thinks is Eli&#8217;s voice is still the right response: total availability, no precondition. Christ&#8217;s &#8220;not my will but yours be done&#8221; (Luke 22:42) is the ultimate <em>hinnēnî</em> — the complete covenant availability of the Son to the Father&#8217;s purpose, even when that purpose includes the cross.</p>",
    "5": "<p>Samuel runs to Eli saying &#8220;Here I am, for you called me&#8221; — but Eli says he did not call. The threefold misidentification (vv5-8) before correct identification is the OT pattern of prophetic formation: the call must be recognized through a process of discernment. The disciples&#8217; misidentification of Jesus throughout the Gospel narratives — mistaking him for a ghost on the water (Matt 14:26), not understanding his predictions of death and resurrection — is the same formation pattern. Understanding who calls and what the call means is the work of a lifetime of discipleship, not immediate comprehension.</p>",
    "6": "<p>YHWH calls Samuel again; Samuel runs to Eli again. The second misidentification deepens the pattern without altering Samuel&#8217;s posture: his <em>hinnēnî</em> (here I am) and his running toward what he thinks is the source of the call are correct even when the identification is wrong. The persistence of the call and the persistence of the response despite misunderstanding is the structure of covenant pursuit: YHWH calls, the called one responds, the relationship deepens through the very process of discernment. Christ&#8217;s disciples repeatedly misunderstood his teaching (Mark 9:32: &#8220;they did not understand the saying, and were afraid to ask him&#8221;) while still following — the running without full understanding that characterizes early discipleship.</p>",
    "7": "<p>&#8220;Now Samuel did not yet know YHWH, and the word of YHWH had not yet been revealed to him.&#8221; The not-yet-knowing is circumstantial — it will be remedied in this very night — in contrast to the sons of Eli whose not-knowing (2:12) was permanent and culpable. The theology of progressive revelation: there is a &#8220;not yet&#8221; in the history of YHWH&#8217;s self-disclosure that is not failure but preparation. The disciples &#8220;did not understand any of these things&#8221; about Christ&#8217;s death and resurrection &#8220;until these things happened&#8221; (Luke 18:34; 24:8) — the not-yet of genuine progressive understanding being overcome by the Spirit (John 16:13: &#8220;he will guide you into all truth&#8221;).</p>",
    "8": "<p>YHWH calls Samuel a third time; Eli perceives that YHWH is calling the boy. The pattern of three calls before recognition echoes throughout sacred narrative: Peter&#8217;s threefold denial is reversed in Christ&#8217;s threefold &#8220;do you love me?&#8221; (John 21:15-17), restoring Peter to exactly the three-count denial. The number three in OT call narratives (three calls before identification) corresponds to the three-day pattern of death and resurrection — the process of dying to old misidentification and rising to true recognition. Eli&#8217;s eventual discernment, however dim his eyes, points to the moment when full recognition arrives.</p>",
    "9": "<p>Eli instructs Samuel: &#8220;Go, lie down, and if he calls you, you shall say, &#8216;Speak, YHWH, for your servant hears.&#8217;&#8221; The response-formula Eli prescribes — &#8220;speak, YHWH, for your servant hears&#8221; — is the model of receptive obedience to divine speech. Isaiah&#8217;s response (Isa 6:8: &#8220;Here I am; send me&#8221;) and Mary&#8217;s (Luke 1:38: &#8220;Let it be to me according to your word&#8221;) are the supreme NT expressions of this posture. Christ&#8217;s entire earthly life is the living expression of &#8220;speak, Father, for your servant hears&#8221;: &#8220;I have come down from heaven not to do my own will but the will of him who sent me&#8221; (John 6:38).</p>",
    "10": "<p>YHWH comes and stands, calling as before: &#8220;Samuel! Samuel!&#8221; — the doubled name of urgent divine address. Samuel responds: &#8220;Speak, for your servant hears&#8221; — the learned formula, now properly directed to YHWH. The theophanic appearance (YHWH comes and stands, <em>wayyāḇōʾ wayyiṯyaṣṣēḇ</em>) is the personal divine presence that initiates the prophetic relationship. Saul&#8217;s Damascus road encounter with the risen Christ (Acts 9:4: &#8220;Saul, Saul, why are you persecuting me?&#8221;) uses the same doubled-name formula. The risen Christ who stops Saul in his tracks and initiates his prophetic call is the YHWH who stood and called Samuel — the same divine person in the fullness of revelation.</p>",
    "11": "<p>&#8220;Behold, I am about to do something in Israel at which the two ears of everyone who hears it will tingle.&#8221; The ear-tingling oracle announces a divine act of such severity that it will be received as a physical shock by every hearer. Christ&#8217;s announcement of Jerusalem&#8217;s destruction (Matt 24:2: &#8220;not one stone will be left on another&#8221;) produces the same stunned response from his disciples (v3: &#8220;when will these things be?&#8221;). The prophetic pattern: YHWH announces the historically unthinkable before it occurs, so that when it happens, the divine word is validated and YHWH&#8217;s sovereign foreknowledge is demonstrated.</p>",
    "12": "<p>&#8220;On that day I will carry out against Eli everything I have spoken concerning his house, from beginning to end.&#8221; The total fulfillment of the prophetic word — nothing held back, nothing softened — is YHWH&#8217;s covenant faithfulness in judgment as well as blessing. The consistency of divine word and historical event is the basis for prophetic authority. Peter applies this principle to Christ&#8217;s death: &#8220;this Jesus, delivered up according to the definite plan and foreknowledge of God, you crucified and killed by the hands of lawless men&#8221; (Acts 2:23) — what YHWH spoke through the prophets concerning the suffering of the Messiah was carried out from beginning to end.</p>",
    "13": "<p>&#8220;I have told him that I am about to judge his house forever for the iniquity that he knew, because his sons were blaspheming God, and he did not restrain them.&#8221; The charge is not that Eli sinned as his sons did but that he knew and did not act. The passive complicity of the one who knows and fails to restrain is itself covenant unfaithfulness. James 4:17: &#8220;whoever knows the right thing to do and fails to do it, for him it is sin.&#8221; Christ&#8217;s faithfulness in contrast: he not only knew what was happening in the temple and spoke against it, he also acted — the cleansing is knowledge acted upon.</p>",
    "14": "<p>&#8220;The iniquity of Eli&#8217;s house shall never be atoned for by sacrifice or offering forever.&#8221; The impossibility of atoning for this particular sin by the very system his sons corrupted points to the limits of the Levitical sacrificial system — limits that the book of Hebrews develops systematically. Heb 10:4: &#8220;it is impossible for the blood of bulls and goats to take away sins.&#8221; The sin that the Levitical system cannot atone requires the better sacrifice — Christ&#8217;s once-for-all offering (Heb 10:10-14) — that accomplishes what the sacrificial system could only gesture toward.</p>",
    "15": "<p>Samuel lay until morning and opened the sanctuary doors — his regular duties performed without alteration despite the overwhelming oracle received. He is afraid to tell Eli the vision. The faithful prophet who carries a difficult word and feels its weight — afraid to speak it to the one it concerns — is the prototype of every NT messenger who bears the gospel&#8217;s both-difficult-and-glorious content. Paul: &#8220;I am not ashamed of the gospel&#8221; (Rom 1:16) — the explicit overcoming of the fear Samuel feels, enabled by the resurrection&#8217;s final reversal of the devastating pattern that Eli represents.</p>",
    "16": "<p>Eli calls &#8220;Samuel, my son!&#8221; — the paternal address that invokes the relationship built over years of sanctuary service. Samuel responds <em>hinnēnî</em> — the same availability formula he used with YHWH. His responsiveness to both divine and human authority, using the same formula, shows the integration of vertical and horizontal covenant loyalty. Christ&#8217;s honoring of both his Father&#8217;s authority and legitimate human authority (Luke 2:51: &#8220;he went down with them and was submissive to them&#8221;) — while maintaining the priority of the Father&#8217;s business (2:49) — models the same integrated covenant posture.</p>",
    "17": "<p>Eli&#8217;s covenant oath — &#8220;God do so to you and more also if you hide anything from me&#8221; — legally binds Samuel to full disclosure. The self-imprecation oath that compels complete truth-telling is the instrument that ensures YHWH&#8217;s word is transmitted without softening. Christ&#8217;s &#8220;But I say to you, do not swear at all... let what you say be simply &#8216;yes&#8217; or &#8216;no&#8217;&#8221; (Matt 5:34,37) addresses a different issue — casual oath-swearing — but the underlying principle is the same: total truthfulness in speech that needs no oath to enforce it. Christ himself speaks with the authority that needs no oath (&#8220;truly I say to you&#8221;) because his word is self-authenticating.</p>",
    "18": "<p>Samuel tells Eli everything and hides nothing. Eli&#8217;s response: &#8220;He is YHWH. Let him do what seems good to him.&#8221; The theological submission — accepting YHWH&#8217;s judgment as &#8220;good&#8221; even when devastating — is Eli&#8217;s finest moment and his last significant speech. Gethsemane: &#8220;not my will but yours be done&#8221; (Luke 22:42) is the perfected form of Eli&#8217;s submission. The difference: Christ&#8217;s submission is not passive acceptance of deserved judgment but active embrace of undeserved suffering for the salvation of others — the same verbal formula expressing infinitely different content.</p>",
    "19": "<p>&#8220;Samuel grew, and YHWH was with him and let none of his words fall to the ground (<em>nāpal ʾārṣāh</em>).&#8221; The prophetic reliability — every word fulfilled, none falling without accomplishing its purpose — is the prophetic standard (Deut 18:22) that Samuel meets from his first oracle. Isaiah 55:11 applies this principle to YHWH&#8217;s word itself: &#8220;it shall not return to me empty, but it shall accomplish that which I purpose.&#8221; Christ is himself the word of YHWH that accomplishes its complete purpose — not one jot or tittle will pass from the law until all is accomplished (Matt 5:18); his words will not pass away (Matt 24:35).</p>",
    "20": "<p>&#8220;And all Israel from Dan to Beersheba knew that Samuel had been established as a prophet (<em>nāḇîʾ</em>) of YHWH.&#8221; The national recognition of Samuel&#8217;s prophetic authority follows directly from YHWH&#8217;s establishment of his words. The nation&#8217;s acknowledgment is secondary; YHWH&#8217;s establishment is primary. Christ&#8217;s authority is similarly established by the Father before and independent of human recognition: &#8220;You are my beloved Son&#8221; (Mark 1:11; Matt 17:5) is the divine establishment that precedes and grounds any human acknowledgment. The crowd&#8217;s recognition of Jesus&#8217;s authority (Matt 7:28-29: &#8220;he taught them as one who had authority&#8221;) follows from YHWH&#8217;s prior establishment.</p>",
    "21": "<p>&#8220;And YHWH continued to appear at Shiloh, for YHWH revealed himself to Samuel at Shiloh through the word of YHWH.&#8221; The sustained prophetic revelation at Shiloh through Samuel marks the end of the prophetic silence and the beginning of the age of classical prophecy. The triple revelation vocabulary — appeared, revealed, word — describes the comprehensive self-disclosure. John 1:14-18 is the ultimate triple revelation: the Word became flesh (appeared), he has made the Father known (<em>exēgeomai</em>, fully explained/revealed), the word of YHWH is now the Word who is YHWH. Samuel&#8217;s Shiloh revelations are the first sustained instance of the pattern that finds its permanent fulfillment in the incarnation.</p>"
  }
}

def main():
    c = load_comm('christ', '1samuel')
    merge_comm(c, CHRIST)
    save_comm('christ', '1samuel', c)
    total = sum(len(v) for v in CHRIST.values())
    print(f'1samuel mkt-christ: wrote {total} verses across ch 1-3')

if __name__ == '__main__':
    main()
